package sqlc

import (
	"context"
	"time"

	"github.com/jackc/pgx/v5/pgtype"
)

// ─── structs ──────────────────────────────────────────────────────────────────
// NOTE: MaintenanceFrequencyEnum and MaintenanceOrderStatusEnum are generated by
// sqlc in models.go. Do NOT redeclare them here.

type DBMaintenancePlan struct {
	ID              int64
	Code            int64
	MachineID       int64
	WorkCenterID    pgtype.Int8
	Description     string
	Frequency       MaintenanceFrequencyEnum
	FrequencyDays   int32
	EstimatedHours  float64
	LastExecutedAt  pgtype.Timestamptz
	NextScheduledAt pgtype.Timestamptz
	IsActive        bool
	CreatedAt       pgtype.Timestamptz
	UpdatedAt       pgtype.Timestamptz
	CreatedBy       pgtype.UUID
}

type DBMaintenanceOrder struct {
	ID             int64
	PlanID         int64
	MachineID      pgtype.Int8
	WorkCenterID   pgtype.Int8
	ScheduledDate  pgtype.Date
	EstimatedHours float64
	ActualHours    pgtype.Float8
	Status         MaintenanceOrderStatusEnum
	StartedAt      pgtype.Timestamptz
	CompletedAt    pgtype.Timestamptz
	Notes          pgtype.Text
	IsActive       bool
	CreatedAt      pgtype.Timestamptz
	UpdatedAt      pgtype.Timestamptz
}

// ─── maintenance_plans ────────────────────────────────────────────────────────

const createMaintenancePlan = `
INSERT INTO maintenance_plans
(machine_id, work_center_id, description, frequency, frequency_days, estimated_hours, next_scheduled_at, created_by)
VALUES ($1,$2,$3,$4,$5,$6,$7,$8)
RETURNING id, code, machine_id, work_center_id, description, frequency, frequency_days, estimated_hours,
          last_executed_at, next_scheduled_at, is_active, created_at, updated_at, created_by`

type CreateMaintenancePlanParams struct {
	MachineID       int64
	WorkCenterID    pgtype.Int8
	Description     string
	Frequency       MaintenanceFrequencyEnum
	FrequencyDays   int32
	EstimatedHours  float64
	NextScheduledAt pgtype.Timestamptz
	CreatedBy       pgtype.UUID
}

func (q *Queries) CreateMaintenancePlan(ctx context.Context, arg CreateMaintenancePlanParams) (DBMaintenancePlan, error) {
	row := q.db.QueryRow(ctx, createMaintenancePlan,
		arg.MachineID, arg.WorkCenterID, arg.Description, arg.Frequency,
		arg.FrequencyDays, arg.EstimatedHours, arg.NextScheduledAt, arg.CreatedBy,
	)
	return scanMaintenancePlan(row)
}

const updateMaintenancePlan = `
UPDATE maintenance_plans SET
    description     = $2,
    frequency       = $3,
    frequency_days  = $4,
    estimated_hours = $5,
    next_scheduled_at = $6,
    updated_at      = NOW()
WHERE id = $1
RETURNING id, code, machine_id, work_center_id, description, frequency, frequency_days, estimated_hours,
          last_executed_at, next_scheduled_at, is_active, created_at, updated_at, created_by`

type UpdateMaintenancePlanParams struct {
	ID              int64
	Description     string
	Frequency       MaintenanceFrequencyEnum
	FrequencyDays   int32
	EstimatedHours  float64
	NextScheduledAt pgtype.Timestamptz
}

func (q *Queries) UpdateMaintenancePlan(ctx context.Context, arg UpdateMaintenancePlanParams) (DBMaintenancePlan, error) {
	row := q.db.QueryRow(ctx, updateMaintenancePlan,
		arg.ID, arg.Description, arg.Frequency, arg.FrequencyDays, arg.EstimatedHours, arg.NextScheduledAt,
	)
	return scanMaintenancePlan(row)
}

const getMaintenancePlanByID = `
SELECT id, code, machine_id, work_center_id, description, frequency, frequency_days, estimated_hours,
       last_executed_at, next_scheduled_at, is_active, created_at, updated_at, created_by
FROM maintenance_plans WHERE id = $1`

func (q *Queries) GetMaintenancePlanByID(ctx context.Context, id int64) (DBMaintenancePlan, error) {
	row := q.db.QueryRow(ctx, getMaintenancePlanByID, id)
	return scanMaintenancePlan(row)
}

const listMaintenancePlans = `
SELECT id, code, machine_id, work_center_id, description, frequency, frequency_days, estimated_hours,
       last_executed_at, next_scheduled_at, is_active, created_at, updated_at, created_by
FROM maintenance_plans
WHERE ($1::boolean IS NULL OR is_active = $1)
ORDER BY machine_id, next_scheduled_at`

func (q *Queries) ListMaintenancePlans(ctx context.Context, onlyActive *bool) ([]DBMaintenancePlan, error) {
	rows, err := q.db.Query(ctx, listMaintenancePlans, onlyActive)
	if err != nil {
		return nil, err
	}
	defer rows.Close()
	return scanMaintenancePlans(rows)
}

const listMaintenancePlansByMachine = `
SELECT id, code, machine_id, work_center_id, description, frequency, frequency_days, estimated_hours,
       last_executed_at, next_scheduled_at, is_active, created_at, updated_at, created_by
FROM maintenance_plans WHERE machine_id = $1 AND is_active = TRUE
ORDER BY next_scheduled_at`

func (q *Queries) ListMaintenancePlansByMachine(ctx context.Context, machineID int64) ([]DBMaintenancePlan, error) {
	rows, err := q.db.Query(ctx, listMaintenancePlansByMachine, machineID)
	if err != nil {
		return nil, err
	}
	defer rows.Close()
	return scanMaintenancePlans(rows)
}

const deactivateMaintenancePlan = `UPDATE maintenance_plans SET is_active=FALSE, updated_at=NOW() WHERE id=$1`

func (q *Queries) DeactivateMaintenancePlan(ctx context.Context, id int64) error {
	_, err := q.db.Exec(ctx, deactivateMaintenancePlan, id)
	return err
}

