const listMaintenanceOrdersByWorkCenter = `
SELECT id, plan_id, machine_id, work_center_id, scheduled_date, estimated_hours, actual_hours,
       status, started_at, completed_at, notes, is_active, created_at, updated_at
FROM maintenance_orders
WHERE work_center_id = $1 AND scheduled_date BETWEEN $2 AND $3 AND is_active = TRUE
ORDER BY scheduled_date`

func (q *Queries) ListMaintenanceOrdersByWorkCenter(ctx context.Context, workCenterID int64, from, to pgtype.Date) ([]DBMaintenanceOrder, error) {
	rows, err := q.db.Query(ctx, listMaintenanceOrdersByWorkCenter, workCenterID, from, to)
	if err != nil {
		return nil, err
	}
	defer rows.Close()
	return scanMaintenanceOrders(rows)
}

const existsOrderForPlanAndDate = `
SELECT EXISTS(
    SELECT 1 FROM maintenance_orders
    WHERE plan_id = $1
      AND scheduled_date = $2::date
      AND status <> 'CANCELLED'
      AND is_active = TRUE
)`

func (q *Queries) ExistsOrderForPlanAndDate(ctx context.Context, planID int64, date time.Time) (bool, error) {
	row := q.db.QueryRow(ctx, existsOrderForPlanAndDate, planID, date.Format("2006-01-02"))
	var exists bool
	err := row.Scan(&exists)
	return exists, err
}

// GetBlockedHoursOnDate returns sum of estimated_hours for planned/in-progress
// maintenance orders for a work center on a specific date — used by CRP.
const getBlockedHoursOnDate = `
SELECT COALESCE(SUM(estimated_hours), 0)
FROM maintenance_orders
WHERE work_center_id = $1
  AND scheduled_date = $2::date
  AND status IN ('PLANNED', 'IN_PROGRESS')
  AND is_active = TRUE`

func (q *Queries) GetBlockedHoursOnDate(ctx context.Context, workCenterID int64, date time.Time) (float64, error) {
	row := q.db.QueryRow(ctx, getBlockedHoursOnDate, workCenterID, date.Format("2006-01-02"))
	var hours float64
	err := row.Scan(&hours)
	return hours, err
}

// ─── scanners ─────────────────────────────────────────────────────────────────

type scannerRow interface{ Scan(...any) error }

func scanMaintenancePlan(row scannerRow) (DBMaintenancePlan, error) {
	var i DBMaintenancePlan
	err := row.Scan(
		&i.ID, &i.Code, &i.MachineID, &i.WorkCenterID, &i.Description,
		&i.Frequency, &i.FrequencyDays, &i.EstimatedHours,
		&i.LastExecutedAt, &i.NextScheduledAt, &i.IsActive,
		&i.CreatedAt, &i.UpdatedAt, &i.CreatedBy,
	)
	return i, err
}

func scanMaintenancePlans(rows interface {
	Next() bool
	Scan(...any) error
	Err() error
}) ([]DBMaintenancePlan, error) {
	var items []DBMaintenancePlan
	for rows.Next() {
		p, err := scanMaintenancePlan(rows)
		if err != nil {
			return nil, err
		}
		items = append(items, p)
	}
	return items, rows.Err()
}

func scanMaintenanceOrder(row scannerRow) (DBMaintenanceOrder, error) {
	var i DBMaintenanceOrder
	err := row.Scan(
		&i.ID, &i.PlanID, &i.MachineID, &i.WorkCenterID, &i.ScheduledDate,
		&i.EstimatedHours, &i.ActualHours, &i.Status,
		&i.StartedAt, &i.CompletedAt, &i.Notes,
		&i.IsActive, &i.CreatedAt, &i.UpdatedAt,
	)
	return i, err
}

func scanMaintenanceOrders(rows interface {
	Next() bool
	Scan(...any) error
	Err() error
}) ([]DBMaintenanceOrder, error) {
	var items []DBMaintenanceOrder
	for rows.Next() {
		o, err := scanMaintenanceOrder(rows)
		if err != nil {
			return nil, err
		}
		items = append(items, o)
	}
	return items, rows.Err()
}
